import vex
import json
from datetime import datetime, timedelta

grounding_guardrail = vex.Guardrail("bing-freshness-edu", 
    rules={
        "date_check": {
            "max_age_days": 30,
            "block_old": True
        },
        "bias_check": ["age_inappropriate", "cultural_bias"]
    })

def validate_bing_grounding(grounding_data: str):
    result = grounding_guardrail.validate(grounding_data)
    if result.is_blocked:
        return {
            "status": "blocked",
            "reason": result.block_reason,
            "timestamp": datetime.now().isoformat()
        }
    return {"status": "approved", "content": result.content}

import { VexClient, Guardrail } from '@vex/sdk';
import { AzureProjectsClient } from '@azure/ai-projects';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });
const tokenGuardrail = await vex.guardrail('agent-token-limit-edu', {
  rules: {
    tokenLimit: 128000,
    degradation: ['summarize_thread', 'restart_conversation']
  }
});

const projectsClient = new AzureProjectsClient({
  credential: defaultAzureCredential,
  subscriptionId: process.env.AZURE_SUB_ID!,
  resourceGroup: process.env.RESOURCE_GROUP!,
  projectName: process.env.PROJECT_NAME!
});

export async function safeAgentComplete(
  threadId: string,
  message: string
): Promise<string> {
  const agentResponse = await projectsClient.agents.completeThread(
    process.env.PROJECT_NAME!,
    'education-tutor',
    threadId,
    message
  );

  const validation = await tokenGuardrail.validate(agentResponse.content);
  if (validation.isBlocked) {
    return `Thread approaching limit. ${validation.suggestion}`;
  }
  return validation.content;
}
